def validate_redirect_uri(redirect_uri, tenant_config):
    """
    Securely validate redirect_uri against tenant configuration.

    SECURITY NOTE: We do NOT use 'if domain in redirect_uri' because
    substring matching is vulnerable to bypass attacks:
      - "https://evil.com?example.com" contains "example.com" ✗
      - "https://example.com.evil.com/callback" contains "example.com" ✗
      - "https://notexample.com/callback" contains "example.com" ✗

    Instead, we:
      1. Parse the URL properly
      2. Enforce HTTPS scheme
      3. Check exact domain match (or exact subdomain match)
      4. Optionally check against an allowlist of exact URIs
    """
    if not redirect_uri:
        return False, "redirect_uri is required"

    try:
        parsed = urlparse(redirect_uri)
    except Exception:
        return False, "Invalid redirect_uri format"

    # 1. Enforce HTTPS (never allow HTTP in production)
    if parsed.scheme != "https":
        return False, "redirect_uri must use HTTPS scheme"

    # 2. Reject URIs with fragments (OAuth 2.0 spec requirement)
    if parsed.fragment:
        return False, "redirect_uri must not contain a fragment"

    # 3. Reject URIs with userinfo (e.g., https://user@evil.com)
    if parsed.username or parsed.password:
        return False, "redirect_uri must not contain userinfo"

    # 4. Ensure hostname is present and valid
    hostname = parsed.hostname
    if not hostname:
        return False, "redirect_uri must contain a valid hostname"

    # 5. SECURE domain validation - exact match only
    # This is the critical fix: we compare the *parsed* hostname exactly
    allowed_domains = tenant_config.get("allowed_domains", [])
    domain_valid = hostname in allowed_domains

    if not domain_valid:
        return False, f"redirect_uri hostname '{hostname}' is not in allowed domains"

    # 6. Optionally enforce exact URI allowlist (strongest protection)
    allowed_uris = tenant_config.get("allowed_redirect_uris", [])
    if allowed_uris:
        # Normalize for comparison: strip trailing slashes
        normalized_uri = redirect_uri.rstrip("/")
        normalized_allowed = [uri.rstrip("/") for uri in allowed_uris]
        if normalized_uri not in normalized_allowed:
            return False, "redirect_uri does not match any allowed redirect URI"

    # 7. Reject suspicious patterns
    if ".." in parsed.path:
        return False, "redirect_uri contains path traversal"

    # Reject open redirect patterns in query params
    if parsed.query:
        query_params = parse_qs(parsed.query)
        suspicious_params = ["url", "redirect", "next", "goto", "return", "returnto"]
        for param in suspicious_params:
            if param in query_params:
                return False, f"redirect_uri contains suspicious query parameter: {param}"

    return True, "Valid"


