def require_tenant(f):
    """Decorator to extract and validate tenant from the route."""
    @wraps(f)
    def decorated_function(tenant_id, *args, **kwargs):
        if tenant_id not in TENANT_CONFIGS:
            abort(404, description=f"Tenant '{tenant_id}' not found")
        return f(tenant_id, *args, **kwargs)
    return decorated_function


def require_authenticated(f):
    """Decorator to require an authenticated session."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "access_token" not in session:
            return jsonify({"error": "Not authenticated"}), 401
        return f(*args, **kwargs)
    return decorated_function


