@app.route("/oauth/<tenant_id>/authorize")
@require_tenant
def authorize(tenant_id):
    """
    Initiate the OAuth 2.0 Authorization Code flow with PKCE.

    Query params:
        redirect_uri: The redirect URI to use (must match tenant config)
    """
    tenant_config = TENANT_CONFIGS[tenant_id]

    # Get redirect_uri from request
    redirect_uri = request.args.get("redirect_uri")
    if not redirect_uri:
        # Fall back to first configured redirect URI
        allowed_uris = tenant_config.get("allowed_redirect_uris", [])
        if allowed_uris:
            redirect_uri = allowed_uris[0]
        else:
            return jsonify({"error": "No redirect_uri provided and none configured"}), 400

    # === SECURE VALIDATION ===
    # This replaces the insecure 'if domain in redirect_uri' check
    is_valid, validation_message = validate_redirect_uri(redirect_uri, tenant_config)
    if not is_valid:
        app.logger.warning(
            f"Rejected redirect_uri for tenant {tenant_id}: "
            f"uri='{redirect_uri}', reason='{validation_message}'"
        )
        return jsonify({
            "error": "invalid_redirect_uri",
            "message": validation_message,
            # Don't echo back the full URI to prevent reflected XSS
            "hint": f"Allowed domains: {tenant_config.get('allowed_domains', [])}",
        }), 400

    # Generate PKCE pair
    code_verifier, code_challenge = generate_pkce_pair()

    # Generate state parameter for CSRF protection
    state = secrets.token_urlsafe(32)

    # Generate nonce for replay protection
    nonce = secrets.token_urlsafe(32)

    # Store in session for later verification
    session["oauth_state"] = state
    session["oauth_nonce"] = nonce
    session["oauth_code_verifier"] = code_verifier
    session["oauth_redirect_uri"] = redirect_uri
    session["oauth_tenant_id"] = tenant_id

    # Build authorization URL
    auth_params = {
        "response_type": "code",
        "client_id": tenant_config["client_id"],
        "redirect_uri": redirect_uri,
        "scope": tenant_config["scopes"],
        "state": state,
        "nonce": nonce,
        "code_challenge": code_challenge,
        "code_challenge_method": "S256",
    }

    authorization_url = f"{tenant_config['authorization_endpoint']}?{urlencode(auth_params)}"

    app.logger.info(f"Initiating OAuth flow for tenant {tenant_id} with redirect_uri: {redirect_uri}")

    return redirect(authorization_url)


@app.route("/oauth/<tenant_id>/callback")
@require_tenant
def callback(tenant_id):
    """
    Handle the OAuth 2.0 authorization callback.
    Exchange authorization code for tokens.
    """
    # Verify state to prevent CSRF
    state = request.args.get("state")
    stored_state = session.pop("oauth_state", None)

    if not state or not stored_state or not secrets.compare_digest(state, stored_state):
        app.logger.warning(f"State mismatch for tenant {tenant_id}. Possible CSRF attack.")
        return jsonify({"error": "Invalid state parameter. Possible CSRF attack."}), 403

    # Check for errors from the authorization server
    error = request.args.get("error")
    if error:
        error_description = request.args.get("error_description", "No description")
        app.logger.error(f"Authorization error for tenant {tenant_id}: {error} - {error_description}")
        return jsonify({
            "error": error,
            "error_description": error_description,
        }), 400

    # Get authorization code
    code = request.args.get("code")
    if not code:
        return jsonify({"error": "No authorization code received"}), 400

    # Retrieve stored values
    code_verifier = session.pop("oauth_code_verifier", None)
    stored_redirect_uri = session.pop("oauth_redirect_uri", None)
    stored_tenant_id = session.pop("oauth_tenant_id", None)

    # Verify tenant consistency
    if stored_tenant_id != tenant_id:
        app.logger.warning(f"Tenant mismatch: expected {stored_tenant_id}, got {tenant_id}")
        return jsonify({"error": "Tenant mismatch"}), 403

    if not code_verifier or not stored_redirect_uri:
        return jsonify({"error": "Missing session data. Please restart the flow."}), 400

    tenant_config = TENANT_CONFIGS[tenant_id]

    # Exchange authorization code for tokens
    token_data = {
        "grant_type": "authorization_code",
        "code": code,
        "redirect_uri": stored_redirect_uri,
        "client_id": tenant_config["client_id"],
        "client_secret": tenant_config["client_secret"],
        "code_verifier": code_verifier,
    }

    try:
        token_response = requests.post(
            tenant_config["token_endpoint"],
            data=token_data,
            headers={"Accept": "application/json"},
            timeout=10,
        )
        token_response.raise_for_status()
        tokens = token_response.json()
    except requests.exceptions.RequestException as e:
        app.logger.error(f"Token exchange failed for tenant {tenant_id}: {e}")
        return jsonify({"error": "Token exchange failed"}), 502

    # Store tokens in session (in production, use a more secure store)
    session["access_token"] = tokens.get("access_token")
    session["refresh_token"] = tokens.get("refresh_token")
    session["id_token"] = tokens.get("id_token")
    session["token_type"] = tokens.get("token_type")
    session["tenant_id"] = tenant_id

    return jsonify({
        "message": "Authentication successful",
        "tenant_id": tenant_id,
        "token_type": tokens.get("token_type"),
        "scope": tokens.get("scope"),
        # Never expose actual tokens in response in production
    })


@app.route("/oauth/<tenant_id>/userinfo")
@require_tenant
@require_authenticated
def userinfo(tenant_id):
    """Fetch user information from the OAuth provider."""
    tenant_config = TENANT_CONFIGS[tenant_id]
    access_token = session.get("access_token")

    if session.get("tenant_id") != tenant_id:
        return jsonify({"error": "Token not valid for this tenant"}), 403

    try:
        userinfo_response = requests.get(
            tenant_config["userinfo_endpoint"],
            headers={
                "Authorization": f"Bearer {access_token}",
                "Accept": "application/json",
            },
            timeout=10,
        )
        userinfo_response.raise_for_status()
        return jsonify(userinfo_response.json())
    except requests.exceptions.RequestException as e:
        app.logger.error(f"Userinfo request failed for tenant {tenant_id}: {e}")
        return jsonify({"error": "Failed to fetch user info"}), 502


